package com.pos;
import javax.swing.*; import java.awt.*; import java.sql.*;
public class UserReturnPanel extends JPanel {private final UserSession s;private final QueryTableModel m=new QueryTableModel();private final JTable t=new JTable(m);private final JTextField order=new JTextField(7),product=new JTextField(7),qty=new JTextField("1",6),reason=new JTextField(25);
 public UserReturnPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("My Return Requests"),BorderLayout.WEST);JButton refresh=new JButton("Refresh");h.add(refresh,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel f=new JPanel();f.add(new JLabel("Completed Order ID"));f.add(order);f.add(new JLabel("Product ID"));f.add(product);f.add(new JLabel("Qty"));f.add(qty);f.add(new JLabel("Reason"));f.add(reason);JButton submit=new JButton("Request Return");f.add(submit);add(f,BorderLayout.SOUTH);refresh.addActionListener(e->load());submit.addActionListener(e->submit());load();}
 private void load(){try{m.load("SELECT r.return_id,r.return_no,r.order_id,r.return_date,r.reason,r.status,r.total_refund FROM sales_returns r JOIN customer_profiles cp ON cp.customer_id=r.customer_id WHERE cp.user_id=? ORDER BY r.return_id DESC",s.userId);}catch(Exception e){UIUtils.error(this,e);}}
 private void submit(){try(Connection c=DB.getConnection()){int cid=POSService.customerId(s.userId);PreparedStatement v=c.prepareStatement("SELECT oi.unit_price FROM sales_orders o JOIN sales_order_items oi ON oi.order_id=o.order_id WHERE o.order_id=? AND o.customer_id=? AND o.order_status='COMPLETED' AND oi.product_id=?");v.setInt(1,Integer.parseInt(order.getText()));v.setInt(2,cid);v.setInt(3,Integer.parseInt(product.getText()));ResultSet r=v.executeQuery();if(!r.next())throw new SQLException("You can request returns only for your completed order item.");PreparedStatement p=c.prepareStatement("INSERT INTO sales_returns(return_no,order_id,customer_id,return_date,reason,status,total_refund) VALUES(?,?,?,CURDATE(),?,'PENDING',?)",Statement.RETURN_GENERATED_KEYS);p.setString(1,POSService.code("RET"));p.setInt(2,Integer.parseInt(order.getText()));p.setInt(3,cid);p.setString(4,reason.getText());double unit=r.getDouble(1), requested=Double.parseDouble(qty.getText());p.setDouble(5,unit*requested);p.executeUpdate();ResultSet keys=p.getGeneratedKeys();keys.next();PreparedStatement item=c.prepareStatement("INSERT INTO sales_return_items(return_id,product_id,quantity,unit_price,line_total,restock_status) VALUES(?,?,?,?,?,'PENDING')");item.setInt(1,keys.getInt(1));item.setInt(2,Integer.parseInt(product.getText()));item.setDouble(3,requested);item.setDouble(4,unit);item.setDouble(5,unit*requested);item.executeUpdate();Audit.log(s,"REQUEST_RETURN","order="+order.getText());load();UIUtils.info(this,"Return request submitted for staff review.");}catch(Exception e){UIUtils.error(this,e);}}
}
